-- ============================================================================
--  01_extensions.sql - extensions, shared schemas, helper functions, triggers
-- ----------------------------------------------------------------------------
--  Loaded first. Everything below is idempotent (safe to re-run).
-- ============================================================================

CREATE EXTENSION IF NOT EXISTS pgcrypto;   -- gen_random_uuid(), digest(), gen_random_bytes()

-- All schemas created up front so later files can reference across schemas
-- regardless of load order.
CREATE SCHEMA IF NOT EXISTS app;
CREATE SCHEMA IF NOT EXISTS manual;
CREATE SCHEMA IF NOT EXISTS ga_landing;
CREATE SCHEMA IF NOT EXISTS shopify;     -- raw Shopify landing (DAG-written)
CREATE SCHEMA IF NOT EXISTS shopline;    -- raw Shopline landing (DAG-written)
CREATE SCHEMA IF NOT EXISTS odoo;        -- raw Odoo landing (DAG-written)
CREATE SCHEMA IF NOT EXISTS commerce;    -- neutral commerce layer (14_commerce.sql)
CREATE SCHEMA IF NOT EXISTS interaction;

-- ── Auto-update updated_date on every row change ────────────────────────────
CREATE OR REPLACE FUNCTION app.set_updated_date()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_date = NOW();
  RETURN NEW;
END;
$$;

-- ── Stable fingerprint of integration credentials ──────────────────────────
-- Used to enforce "the same credentials can't be connected to two companies in
-- the same account". Caller passes the canonical secret string (e.g. GA
-- propertyId, Shopify "store|token", GSC siteUrl); we store only its hash.
CREATE OR REPLACE FUNCTION app.credential_fingerprint(secret TEXT)
RETURNS TEXT LANGUAGE sql IMMUTABLE AS $$
  SELECT CASE
           WHEN secret IS NULL OR secret = '' THEN NULL
           ELSE encode(digest(lower(trim(secret)), 'sha256'), 'hex')
         END;
$$;

-- ── URL helpers (used by the web-content attributes crawler) ────────────────
-- Percent-decode a URL to readable UTF-8 so encoded/decoded non-ASCII URLs
-- compare equal. Falls back to the input if it isn't valid percent-encoding.
CREATE OR REPLACE FUNCTION app.url_decode(input TEXT)
RETURNS TEXT LANGUAGE plpgsql IMMUTABLE AS $$
DECLARE
  bytes BYTEA := '\x';
  i INT := 1;
  n INT := length(input);
  ch TEXT;
BEGIN
  IF input IS NULL THEN RETURN NULL; END IF;
  WHILE i <= n LOOP
    ch := substr(input, i, 1);
    IF ch = '%' AND i + 2 <= n AND substr(input, i + 1, 2) ~ '^[0-9A-Fa-f]{2}$' THEN
      bytes := bytes || decode(substr(input, i + 1, 2), 'hex');
      i := i + 3;
    ELSE
      bytes := bytes || convert_to(ch, 'UTF8');
      i := i + 1;
    END IF;
  END LOOP;
  RETURN convert_from(bytes, 'UTF8');
EXCEPTION WHEN others THEN
  RETURN input;
END;
$$;

-- Normalise a URL for matching crawled pages against visited page_locations:
-- drop #fragment / ?query / trailing slash, lower-case, strip scheme + leading
-- "www.", and percent-decode (only when a '%' is present).
CREATE OR REPLACE FUNCTION app.norm_url(u TEXT)
RETURNS TEXT LANGUAGE sql IMMUTABLE AS $$
  SELECT regexp_replace(
           rtrim(
             lower(
               CASE WHEN position('%' IN COALESCE(u, '')) > 0
                    THEN app.url_decode(split_part(split_part(u, '#', 1), '?', 1))
                    ELSE split_part(split_part(COALESCE(u, ''), '#', 1), '?', 1)
               END
             ), '/'
           ),
           '^https?://(www\.)?', ''
         );
$$;


-- ========================= 02_accounts_auth.sql =========================

-- ============================================================================
--  02_accounts_auth.sql - tenancy root: Account → Workspace(company) → Member
-- ----------------------------------------------------------------------------
--  Hierarchy:
--    app.accounts        one per signup; owns billing/plan and N workspaces
--      └ app.users           login identities, each belongs to ONE account
--      └ app.companies       "workspaces"; each has its own capsuite_ref +
--                            interaction_service_company_id; fully data-isolated
--          └ app.company_members   (user × company × role) = per-company access
--
--  Every tenant-scoped table elsewhere references app.companies(id) and is
--  NOT NULL on company_id. account_id is denormalised only where account-level
--  uniqueness is required (see 07_integrations.sql).
--
--  DELETION SEMANTICS (the whole point of the FK choices below):
--    • Delete a WORKSPACE (app.companies row): every company-scoped row in app.*
--      AND in the source schemas (manual/ga_landing/shopify/interaction) is
--      removed via ON DELETE CASCADE on company_id. Audit rows are kept but
--      detached (company_id → NULL) so the "workspace deleted" history survives
--      for the remaining admins.
--    • Delete an ACCOUNT (app.accounts row): cascades to users, companies (and
--      therefore all company-scoped data), members, invitations, integrations,
--      audit_log and support_tickets via account_id ON DELETE CASCADE - i.e.
--      ALL data for the account is removed.
--
--  ROLES (app.company_members.role): admin | contributor | viewer
--    • admin       - sees and controls everything in the workspace, AND sets the
--                    `permissions` overrides that gate what contributors/viewers
--                    may view/edit.
--    • contributor - view + edit, but only where admin granted it in permissions.
--    • viewer      - read-only; never edits (enforced in app middleware).
--  The account creator is the account owner (app.accounts.owner_user_id) and is
--  always an admin on every workspace.
-- ============================================================================

-- ── Plans (catalog; account.plan references this by id) ─────────────────────
--  Three tiers: 'lite' ($100/mo, the entry tier carrying a 3-month trial that
--  goes read-only on expiry), 'standard' ($199/mo) and 'pro' (contact sales).
--  There is no in-app payment flow - the paid upgrade is applied out-of-band by
--  sales (set app.accounts.plan + clear plan_expires_at). Trial state is driven
--  by plan_expires_at, not the tier, so any tier could in principle carry one.
CREATE TABLE app.plans (
  id             TEXT        PRIMARY KEY,            -- 'lite' | 'standard' | 'pro'
  name           TEXT        NOT NULL,
  price_display  TEXT        NOT NULL DEFAULT '',
  period         TEXT        NOT NULL DEFAULT '',
  badge          TEXT,
  description    TEXT        NOT NULL DEFAULT '',
  cta_label      TEXT        NOT NULL DEFAULT 'Get started',
  cta_href       TEXT        NOT NULL DEFAULT '/register',
  cta_external   BOOLEAN     NOT NULL DEFAULT false,
  is_highlighted BOOLEAN     NOT NULL DEFAULT false,
  sort_order     INTEGER     NOT NULL DEFAULT 0,
  trial_days     INTEGER,
  warning_days   INTEGER     NOT NULL DEFAULT 7,
  features       JSONB       NOT NULL DEFAULT '[]',
  limits         JSONB       NOT NULL DEFAULT '{}',  -- {profiles, campaigns, ai_tokens, team_members, workspaces}
  is_active      BOOLEAN     NOT NULL DEFAULT true
);

