-- ========================= 04_edm.sql =========================

-- ============================================================================
--  04_edm.sql - Email Direct Marketing (Klaviyo-like)
--  templates · campaigns · per-recipient sends · events · suppression ·
--  automations (+ steps + enrollments). All company_id NOT NULL.
--  edm_sends / edm_events carry a denormalised company_id for simple filtering.
-- ============================================================================

-- ── Templates ───────────────────────────────────────────────────────────────
CREATE TABLE app.edm_templates (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id   UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by   UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  visibility   TEXT        NOT NULL DEFAULT 'private',
  name         TEXT        NOT NULL DEFAULT '',
  subject      TEXT        NOT NULL DEFAULT '',
  preview_text TEXT,
  html_body    TEXT        NOT NULL DEFAULT '',
  text_body    TEXT,
  variables    JSONB       NOT NULL DEFAULT '[]',   -- block/builder metadata
  status       TEXT        NOT NULL DEFAULT 'draft', -- draft | published
  metadata     JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX edm_templates_company_idx ON app.edm_templates(company_id);
CREATE TRIGGER edm_templates_updated_date BEFORE UPDATE ON app.edm_templates
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Campaigns ───────────────────────────────────────────────────────────────
CREATE TABLE app.edm_campaigns (
  id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id       UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by       UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  visibility       TEXT        NOT NULL DEFAULT 'private',
  name             TEXT        NOT NULL DEFAULT '',
  subject          TEXT        NOT NULL DEFAULT '',
  preview_text     TEXT,
  from_name        TEXT        NOT NULL DEFAULT '',
  from_email       TEXT        NOT NULL DEFAULT '',
  reply_to         TEXT,
  template_id      UUID        REFERENCES app.edm_templates(id) ON DELETE SET NULL,
  html_body        TEXT,
  text_body        TEXT,
  segment_id       UUID        REFERENCES app.segments(id) ON DELETE SET NULL,
  utm_campaign_id  UUID        REFERENCES app.campaigns(id) ON DELETE SET NULL,
  status           TEXT        NOT NULL DEFAULT 'draft',  -- draft | scheduled | sending | sent | cancelled | archived
  scheduled_at     TIMESTAMPTZ,
  sent_at          TIMESTAMPTZ,
  total_recipients INTEGER     DEFAULT 0,
  ab_test_config   JSONB       NOT NULL DEFAULT '{}',
  metadata         JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX edm_campaigns_company_idx ON app.edm_campaigns(company_id);
CREATE TRIGGER edm_campaigns_updated_date BEFORE UPDATE ON app.edm_campaigns
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Per-recipient send records ──────────────────────────────────────────────
CREATE TABLE app.edm_sends (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  edm_campaign_id UUID        NOT NULL REFERENCES app.edm_campaigns(id) ON DELETE CASCADE,
  email           TEXT        NOT NULL,
  member_id       TEXT,                              -- → app.customer_profiles.member_id (same company)
  status          TEXT        NOT NULL DEFAULT 'queued',  -- queued | sent | delivered | bounced | failed
  sent_at         TIMESTAMPTZ,
  error_message   TEXT,
  metadata        JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX edm_sends_company_idx  ON app.edm_sends(company_id);
CREATE INDEX edm_sends_campaign_idx ON app.edm_sends(edm_campaign_id);
CREATE INDEX edm_sends_email_idx    ON app.edm_sends(email);

-- ── Events (opens, clicks, bounces, unsubscribes) ───────────────────────────
CREATE TABLE app.edm_events (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  occurred_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  edm_campaign_id UUID        REFERENCES app.edm_campaigns(id) ON DELETE SET NULL,
  send_id         UUID        REFERENCES app.edm_sends(id) ON DELETE SET NULL,
  email           TEXT        NOT NULL,
  event_type      TEXT        NOT NULL,   -- open | click | bounce | complaint | unsubscribe | delivered
  link_url        TEXT,
  metadata        JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX edm_events_company_idx  ON app.edm_events(company_id);
CREATE INDEX edm_events_campaign_idx ON app.edm_events(edm_campaign_id);
CREATE INDEX edm_events_type_idx     ON app.edm_events(event_type);

-- ── Suppression list (per company do-not-send) ──────────────────────────────
CREATE TABLE app.edm_suppression (
  id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  email      TEXT        NOT NULL,
  reason     TEXT        NOT NULL DEFAULT 'manual',   -- bounced | unsubscribed | complained | manual
  -- manual-upload provenance marker (consistent with the manual.* schema rule)
  is_manual  BOOLEAN     NOT NULL DEFAULT false,
  added_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  metadata   JSONB       NOT NULL DEFAULT '{}'
);
CREATE UNIQUE INDEX edm_suppression_company_email_idx ON app.edm_suppression(company_id, LOWER(email));

-- ── Automations (drip flows) ────────────────────────────────────────────────
CREATE TABLE app.edm_automations (
  id             UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id     UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by     UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  visibility     TEXT        NOT NULL DEFAULT 'private',
  name           TEXT        NOT NULL DEFAULT '',
  trigger_type   TEXT        NOT NULL DEFAULT 'manual',  -- manual | schedule | segment_entry
  trigger_config JSONB       NOT NULL DEFAULT '{}',
  segment_id     UUID        REFERENCES app.segments(id) ON DELETE SET NULL,
  status         TEXT        NOT NULL DEFAULT 'draft',   -- draft | active | paused | archived
  metadata       JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX edm_automations_company_idx ON app.edm_automations(company_id);
CREATE TRIGGER edm_automations_updated_date BEFORE UPDATE ON app.edm_automations
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Automation steps ────────────────────────────────────────────────────────
CREATE TABLE app.edm_automation_steps (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  automation_id UUID        NOT NULL REFERENCES app.edm_automations(id) ON DELETE CASCADE,
  created_by    UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  step_order    INTEGER     NOT NULL DEFAULT 0,
  step_type     TEXT        NOT NULL DEFAULT 'send_email',  -- send_email | wait | condition
  step_config   JSONB       NOT NULL DEFAULT '{}',
  next_step_id  UUID,
  created_date  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX edm_automation_steps_automation_idx ON app.edm_automation_steps(automation_id);

-- ── Automation enrollments ──────────────────────────────────────────────────
CREATE TABLE app.edm_automation_enrollments (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  automation_id   UUID        NOT NULL REFERENCES app.edm_automations(id) ON DELETE CASCADE,
  email           TEXT        NOT NULL,
  member_id       TEXT,
  current_step_id UUID        REFERENCES app.edm_automation_steps(id) ON DELETE SET NULL,
  next_run_at     TIMESTAMPTZ,
  enrolled_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  completed_at    TIMESTAMPTZ,
  status          TEXT        NOT NULL DEFAULT 'active',  -- active | completed | cancelled | failed
  metadata        JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX edm_enrollments_automation_idx ON app.edm_automation_enrollments(automation_id);
CREATE INDEX edm_enrollments_next_run_idx   ON app.edm_automation_enrollments(next_run_at) WHERE status = 'active';


-- ========================= 05_popups.sql =========================

-- ============================================================================
--  05_popups.sql - Pop-ups (bridged to the interaction-service microservice)
--  Popup DEFINITIONS live here (app-owned). They are pushed to the
--  interaction-service over HTTP; live activity/leads are read back and the
--  collected emails are cached in app.popup_email_collected.
-- ============================================================================

-- ── Pop-ups ─────────────────────────────────────────────────────────────────
CREATE TABLE app.popups (
  id                     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id             UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by             UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  name                   TEXT        NOT NULL DEFAULT '',
  -- link to the interaction-service record (in the microservice's own DB)
  interaction_service_id UUID,
  interaction_type       TEXT        NOT NULL DEFAULT 'banner',  -- banner | modal | slide_in | notification
  cdp_reference_id       TEXT        NOT NULL DEFAULT '',
  segment_id             UUID        REFERENCES app.segments(id) ON DELETE SET NULL,
  rules                  JSONB       NOT NULL DEFAULT '{}',
  content                TEXT        NOT NULL DEFAULT '',
  default_recommendation JSONB       NOT NULL DEFAULT '{}',
  is_active              BOOLEAN     NOT NULL DEFAULT false,
  is_default             BOOLEAN     NOT NULL DEFAULT false,
  start_time             TIMESTAMPTZ,
  end_time               TIMESTAMPTZ,
  status                 TEXT        NOT NULL DEFAULT 'draft'    -- draft | active | paused | archived
);
CREATE INDEX popups_company_idx ON app.popups(company_id);
CREATE TRIGGER popups_updated_date BEFORE UPDATE ON app.popups
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Pop-up templates ────────────────────────────────────────────────────────
CREATE TABLE app.popup_templates (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by    UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  name          TEXT        NOT NULL DEFAULT '',
  category      TEXT        NOT NULL DEFAULT 'Custom',
  description   TEXT        NOT NULL DEFAULT '',
  content       TEXT        NOT NULL DEFAULT '',
  builder_state JSONB,                                  -- null for HTML-imported templates
  is_builtin    BOOLEAN     NOT NULL DEFAULT false
);
CREATE INDEX popup_templates_company_idx ON app.popup_templates(company_id);
CREATE TRIGGER popup_templates_updated_date BEFORE UPDATE ON app.popup_templates
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Collected emails (leads captured by popups; cache of microservice data) ─
CREATE TABLE app.popup_email_collected (
  id                 UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  collected_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id         UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  popup_id           UUID        REFERENCES app.popups(id) ON DELETE SET NULL,
  popup_name         TEXT,
  popup_ref          TEXT,
  email              TEXT        NOT NULL,
  first_name         TEXT,
  last_name          TEXT,
  phone              TEXT,
  source_url         TEXT,
  page_title         TEXT,
  device_type        TEXT,
  browser            TEXT,
  os                 TEXT,
  country            TEXT,
  city               TEXT,
  region             TEXT,
  visitor_id         TEXT,        -- anonymous id → links to app.anonymous_profiles / profile_identities
  session_id         TEXT,
  ip_address         TEXT,
  utm_source         TEXT,
  utm_medium         TEXT,
  utm_campaign       TEXT,
  utm_term           TEXT,
  utm_content        TEXT,
  status             TEXT        NOT NULL DEFAULT 'new',  -- new | contacted | converted | unsubscribed
  notes              TEXT,
  -- lineage: how this email became (or matched) a customer profile
  profile_created    BOOLEAN     NOT NULL DEFAULT false,
  profile_created_at TIMESTAMPTZ,
  profile_id         TEXT,        -- member_id of the matched/created customer profile
  profile_lineage    JSONB       NOT NULL DEFAULT '{}',
  metadata           JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX popup_email_collected_company_idx   ON app.popup_email_collected(company_id);
CREATE INDEX popup_email_collected_popup_idx     ON app.popup_email_collected(popup_id);
CREATE INDEX popup_email_collected_email_idx     ON app.popup_email_collected(LOWER(email));
CREATE INDEX popup_email_collected_collected_idx ON app.popup_email_collected(collected_at DESC);


-- ========================= 06_attributes.sql =========================

-- ============================================================================
--  06_attributes.sql - custom targeting dimensions (the /attributes page)
--  Three sources attach a value to a profile:
--    web_content : AI tags each crawled page; visitors inherit tags from pages
--                  they viewed (propagates to anonymous visitors too)
--    rule        : a condition over profile fields (reuses segment criteria)
--    manual      : value assigned by hand / CSV (see also manual.* schema)
--  app.profile_attribute_values is the single source of truth for segmentation.
--  The JSONB caches on customer_profiles are display-only.
-- ============================================================================

-- ── Attribute definitions ───────────────────────────────────────────────────
CREATE TABLE app.attributes (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by      UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  name            TEXT        NOT NULL DEFAULT '',
  description     TEXT        NOT NULL DEFAULT '',      -- doubles as the AI instruction
  source          TEXT        NOT NULL DEFAULT 'web_content', -- web_content | rule | manual
  value_type      TEXT        NOT NULL DEFAULT 'multi',       -- single | multi
  status          TEXT        NOT NULL DEFAULT 'draft',       -- draft | active | archived
  scope           TEXT        NOT NULL DEFAULT 'both',        -- customer | anonymous | both
  extract_from    TEXT        NOT NULL DEFAULT 'both',        -- title | content | both
  group_label     TEXT,                                       -- optional grouping dimension
  content_applied BOOLEAN     NOT NULL DEFAULT false,         -- true once tags have been applied to content → locks extract_from/value_type
  rule            JSONB       NOT NULL DEFAULT '{}',          -- for source='rule'
  last_run_date   TIMESTAMPTZ,
  last_run_status TEXT,                                       -- success | failed | running
  metadata        JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX attributes_company_idx ON app.attributes(company_id, source);
-- Attribute names are unique within a workspace (case-insensitive).
CREATE UNIQUE INDEX attributes_company_lower_name_idx ON app.attributes(company_id, lower(name));
CREATE TRIGGER attributes_updated_date BEFORE UPDATE ON app.attributes
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Attribute values (curated + AI-discovered exceptions) ───────────────────
CREATE TABLE app.attribute_values (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  attribute_id  UUID        NOT NULL REFERENCES app.attributes(id) ON DELETE CASCADE,
  value         TEXT        NOT NULL,
  display_label TEXT,
  group_name    TEXT,                                  -- group under attribute.group_label
  is_exception  BOOLEAN     NOT NULL DEFAULT false,    -- AI-discovered, pending review
  is_approved   BOOLEAN     NOT NULL DEFAULT false,    -- curated/approved → used for targeting
  is_blocked    BOOLEAN     NOT NULL DEFAULT false,    -- stoplist: never resurrect/propagate
  merged_into   UUID        REFERENCES app.attribute_values(id) ON DELETE SET NULL,
  page_count    INTEGER     NOT NULL DEFAULT 0,
  profile_count INTEGER     NOT NULL DEFAULT 0,
  metadata      JSONB       NOT NULL DEFAULT '{}'
);
CREATE UNIQUE INDEX attribute_values_unique_idx ON app.attribute_values(attribute_id, LOWER(value));
CREATE TRIGGER attribute_values_updated_date BEFORE UPDATE ON app.attribute_values
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Crawled web pages (behavioral source) ───────────────────────────────────
CREATE TABLE app.web_pages (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id   UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  url             TEXT        NOT NULL,
  title           TEXT,
  content_hash    TEXT,
  excerpt         TEXT,
  content         TEXT,
  word_count      INTEGER     NOT NULL DEFAULT 0,
  is_valid        BOOLEAN     NOT NULL DEFAULT true,      -- overall validity = valid_content AND valid_title
  is_valid_content BOOLEAN    NOT NULL DEFAULT true,      -- body length ≥ min & no error strings
  is_valid_title  BOOLEAN     NOT NULL DEFAULT true,      -- title ≥ valid_title_min_length (default 1) & no error strings
  is_excluded     BOOLEAN     NOT NULL DEFAULT false,     -- "Excluded Pages"
  excluded_type   TEXT,                                   -- exact | pattern (how it was excluded)
  excluded_value  TEXT,                                   -- the URL or pattern that excluded it
  is_manual       BOOLEAN     NOT NULL DEFAULT false,     -- manually added vs crawler-discovered
  needs_retag     BOOLEAN     NOT NULL DEFAULT false,     -- content changed/new → tag phase should re-tag
  fetch_method    TEXT,                                   -- http | browser
  og_updated_time TIMESTAMPTZ,                            -- og:updated_time meta → skip re-scrape when unchanged
  last_crawled    TIMESTAMPTZ,
  last_reviewed_date TIMESTAMPTZ,                         -- when a user last reviewed this page's tags
  metadata        JSONB       NOT NULL DEFAULT '{}'
);
CREATE UNIQUE INDEX web_pages_company_url_idx ON app.web_pages(company_id, url);
CREATE INDEX web_pages_retag_idx ON app.web_pages(company_id) WHERE needs_retag;
CREATE TRIGGER web_pages_updated_date BEFORE UPDATE ON app.web_pages
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Managed test links (dry-run sample set for the Test tab) ─────────────────
-- Up to 50 GA-extracted (last 30 days, valid only) and/or up to 50 manual URLs.
-- Users tick a subset to dry-run an attribute against without persisting.
CREATE TABLE app.web_content_test_links (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id   UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  url          TEXT        NOT NULL,
  title        TEXT,
  source       TEXT        NOT NULL DEFAULT 'manual',  -- ga | manual
  is_selected  BOOLEAN     NOT NULL DEFAULT true,      -- included in the next dry-run
  hits         INTEGER     NOT NULL DEFAULT 0,         -- GA pageviews (for ordering)
  metadata     JSONB       NOT NULL DEFAULT '{}'
);
CREATE UNIQUE INDEX web_content_test_links_company_url_idx ON app.web_content_test_links(company_id, url);
CREATE TRIGGER web_content_test_links_updated_date BEFORE UPDATE ON app.web_content_test_links
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Page-rank rollup (precomputed top pages by GA traffic) ───────────────────
-- The expensive GROUP BY over the event-level ga_landing.path_exploration is run
-- ONCE per day (nightly cron) or on explicit rebuild, and cached here. Test-link
-- refresh + the daily sync then read this table cheaply (ORDER BY hits LIMIT 50)
-- instead of re-aggregating millions of pageview rows on every click.
CREATE TABLE app.web_content_page_rank (
  company_id   UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  url          TEXT        NOT NULL,
  hits         INTEGER     NOT NULL DEFAULT 0,   -- pageviews in the window
  window_days  INTEGER     NOT NULL DEFAULT 30,
  refreshed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, url)
);
CREATE INDEX web_content_page_rank_rank_idx ON app.web_content_page_rank(company_id, hits DESC);

-- ── Page → value tags ───────────────────────────────────────────────────────
CREATE TABLE app.page_attribute_values (
  id                 UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id         UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  page_id            UUID        NOT NULL REFERENCES app.web_pages(id) ON DELETE CASCADE,
  attribute_id       UUID        NOT NULL REFERENCES app.attributes(id) ON DELETE CASCADE,
  attribute_value_id UUID        NOT NULL REFERENCES app.attribute_values(id) ON DELETE CASCADE,
  confidence         REAL
);
CREATE UNIQUE INDEX page_attr_value_unique_idx ON app.page_attribute_values(page_id, attribute_value_id);
CREATE INDEX page_attr_value_attr_idx ON app.page_attribute_values(attribute_id);

-- ── Profile → value tags (THE segmentation source of truth) ─────────────────
-- entity_id points at app.customer_profiles.member_id (entity_type='customer')
-- or app.anonymous_profiles.visitor_id (entity_type='anonymous'), same company.
CREATE TABLE app.profile_attribute_values (
  id                 UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id         UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  entity_type        TEXT        NOT NULL CHECK (entity_type IN ('customer','anonymous')),
  entity_id          TEXT        NOT NULL,
  attribute_id       UUID        NOT NULL REFERENCES app.attributes(id) ON DELETE CASCADE,
  attribute_value_id UUID        NOT NULL REFERENCES app.attribute_values(id) ON DELETE CASCADE,
  source             TEXT        NOT NULL DEFAULT 'web_content', -- web_content | rule | manual
  score              INTEGER     NOT NULL DEFAULT 1,   -- e.g. # supporting pageviews
  first_seen         TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  last_seen          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE UNIQUE INDEX profile_attr_value_unique_idx
  ON app.profile_attribute_values(company_id, entity_type, entity_id, attribute_value_id);
CREATE INDEX profile_attr_value_attr_idx
  ON app.profile_attribute_values(company_id, attribute_id, attribute_value_id);
CREATE INDEX profile_attr_value_entity_idx
  ON app.profile_attribute_values(company_id, entity_type, entity_id);
CREATE TRIGGER profile_attribute_values_updated_date BEFORE UPDATE ON app.profile_attribute_values
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Attribute reconstruct jobs (persisted queue) ────────────────────────────
CREATE TABLE app.attribute_jobs (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  attribute_id  UUID        REFERENCES app.attributes(id) ON DELETE CASCADE,  -- null = all behavioral attrs
  job_type      TEXT        NOT NULL DEFAULT 'behavioral',  -- behavioral (refresh+tag) | refresh (scrape only) | tag (tag only) | retag_attribute (scoped) | rule
  status        TEXT        NOT NULL DEFAULT 'queued',      -- queued | running | completed | failed | cancelled
  phase         TEXT,                                       -- discovering | scraping | tagging | propagating | done
  progress      JSONB       NOT NULL DEFAULT '{}',
  triggered_by  UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  started_at    TIMESTAMPTZ,
  completed_at  TIMESTAMPTZ,
  error_message TEXT,
  metadata      JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX attribute_jobs_company_idx ON app.attribute_jobs(company_id, created_date DESC);
CREATE INDEX attribute_jobs_queued_idx  ON app.attribute_jobs(status, created_date) WHERE status IN ('queued','running');
CREATE TRIGGER attribute_jobs_updated_date BEFORE UPDATE ON app.attribute_jobs
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();


-- ========================= 07_integrations.sql =========================

-- ============================================================================
--  07_integrations.sql - data source connections + sync queue + audit
--  Sources: googleAnalytics, googleSearchConsole, shopify, shopifyCustomApp,
--           wordpress, interactionService, manualUpload.
--  Rule: within one ACCOUNT the same credentials cannot be connected to two
--  companies. Enforced by a unique (account_id, integration_type,
--  credential_fingerprint) index. Also one of each type per company.
-- ============================================================================

CREATE TABLE app.data_integrations (
  id                     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  account_id             UUID        NOT NULL REFERENCES app.accounts(id) ON DELETE CASCADE,
  company_id             UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_by             UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  integration_type       TEXT        NOT NULL,
  config                 JSONB       NOT NULL DEFAULT '{}',
  -- sha256 of the canonical secret part of config (set via app.credential_fingerprint
  -- in the connect route). Enables the per-account uniqueness rule.
  credential_fingerprint TEXT,
  is_connected           BOOLEAN     NOT NULL DEFAULT false,
  last_connected_date    TIMESTAMPTZ,
  last_tested_date       TIMESTAMPTZ,
  is_connection_error    BOOLEAN     NOT NULL DEFAULT false,
  connection_error       TEXT,
  is_synced              BOOLEAN     NOT NULL DEFAULT false,
  last_synced_date       TIMESTAMPTZ,
  is_sync_error          BOOLEAN     NOT NULL DEFAULT false,
  sync_error             TEXT
);
-- one integration of each type per company
CREATE UNIQUE INDEX data_integrations_company_type_idx
  ON app.data_integrations(company_id, integration_type);
-- the same credentials may not be reused across companies in the same account
CREATE UNIQUE INDEX data_integrations_account_cred_idx
  ON app.data_integrations(account_id, integration_type, credential_fingerprint)
  WHERE credential_fingerprint IS NOT NULL;
CREATE INDEX data_integrations_company_idx ON app.data_integrations(company_id);
CREATE TRIGGER data_integrations_updated_date BEFORE UPDATE ON app.data_integrations
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Integration sync jobs (persisted queue; worker claims with SKIP LOCKED) ─
CREATE TABLE app.integration_sync_jobs (
  id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id       UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  integration_type TEXT        NOT NULL,
  airflow_run_id   TEXT,
  status           TEXT        NOT NULL DEFAULT 'queued',  -- queued | running | completed | failed | cancelled
  triggered_by     TEXT        NOT NULL DEFAULT 'manual',  -- manual | schedule | health_check
  started_at       TIMESTAMPTZ,
  completed_at     TIMESTAMPTZ,
  records_synced   INTEGER,
  error_message    TEXT,
  metadata         JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX sync_jobs_company_type_idx ON app.integration_sync_jobs(company_id, integration_type, created_date DESC);
CREATE INDEX sync_jobs_queued_idx       ON app.integration_sync_jobs(status, created_date) WHERE status IN ('queued','running');
CREATE TRIGGER integration_sync_jobs_updated_date BEFORE UPDATE ON app.integration_sync_jobs
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Integration audit log (immutable history) ───────────────────────────────
CREATE TABLE app.integration_audit_log (
  id               UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  occurred_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id       UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  integration_type TEXT        NOT NULL,
  action           TEXT        NOT NULL,  -- connected | disconnected | connection_failed | reconnected | health_passed | health_failed | sync_queued | sync_completed | sync_failed | sync_cancelled
  actor            TEXT,                  -- user id, 'system', or 'airflow'
  detail           TEXT,
  metadata         JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX audit_log_co_type_idx ON app.integration_audit_log(company_id, integration_type, occurred_at DESC);


-- ========================= 08_manual.sql =========================

-- ============================================================================
--  08_manual.sql - "Manual Upload" data source (schema: manual)
-- ----------------------------------------------------------------------------
--  Everything a user uploads by CSV lands here, company-scoped, and is tagged
--  as manual provenance via upload_batch_id (+ is_manual=true). The unified
--  profile builder reads manual.membership alongside commerce.customer.
--
--  Manual upload is supported for:
--    • Customer profiles / membership  → manual.membership
--    • Sales / orders                  → manual.sale + manual.sale_order_line
--    • Products                        → manual.product
--    • UTM links                       → app.campaigns        (is_manual via metadata)
--    • Email suppression               → app.edm_suppression  (is_manual=true)
--    • Manual attributes               → app.profile_attribute_values (source='manual')
--    • Content attributes / Valid /
--      Excluded pages                  → app.web_pages        (is_manual=true)
--  The rows that live in app.* keep their own manual markers; this schema holds
--  the source-of-record commerce + membership uploads.
-- ============================================================================

-- ── Upload batches (provenance for every CSV import) ────────────────────────
CREATE TABLE manual.upload_batches (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id   UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  uploaded_by  UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  entity_type  TEXT        NOT NULL,   -- membership | sale | product | utm | suppression | attribute | web_page
  file_name    TEXT,
  row_count    INTEGER     NOT NULL DEFAULT 0,
  status       TEXT        NOT NULL DEFAULT 'completed',  -- pending | processing | completed | failed
  error_message TEXT,
  metadata     JSONB       NOT NULL DEFAULT '{}'
);
CREATE INDEX manual_upload_batches_company_idx ON manual.upload_batches(company_id, created_date DESC);

-- ── Members (manual upload) ─────────────────────────────────────────────────
-- Column set kept rich (demographics etc.); the profile builder maps it into
-- app.customer_profiles alongside the synced commerce.customer rows.
-- member_id convention: {capsuite_ref}_man_{n}
CREATE TABLE manual.membership (
  member_id            TEXT        NOT NULL,
  company_id           UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  upload_batch_id      UUID        REFERENCES manual.upload_batches(id) ON DELETE SET NULL,
  is_manual            BOOLEAN     NOT NULL DEFAULT true,
  member_no            TEXT,
  member_join_date     TIMESTAMPTZ,
  member_last_update   TIMESTAMPTZ,
  member_reg_channel   TEXT        DEFAULT 'manual',
  member_reg_location  TEXT,
  member_type          TEXT,
  is_company           BOOLEAN     DEFAULT false,
  has_email            BOOLEAN     DEFAULT false,
  primary_email        TEXT,
  secondary_email      TEXT,
  has_phone            BOOLEAN     DEFAULT false,
  primary_phone        TEXT,
  secondary_phone      TEXT,
  gender               TEXT,
  nationality          TEXT,
  age                  TEXT,
  age_group            TEXT,
  birthday_year        TEXT,
  birthday_month       TEXT,
  birthday_day         TEXT,
  marital_status       TEXT,
  education_level      TEXT,
  income_level         TEXT,
  employment_status    TEXT,
  title                TEXT,
  eng_first_name       TEXT,
  eng_last_name        TEXT,
  eng_full_name        TEXT,
  chi_first_name       TEXT,
  chi_last_name        TEXT,
  chi_full_name        TEXT,
  display_name         TEXT,
  is_subscriber_only   BOOLEAN     DEFAULT false,
  is_opt_in_email      BOOLEAN,
  is_opt_in_call       BOOLEAN,
  is_opt_in_dm         BOOLEAN,
  is_opt_in_sms        BOOLEAN,
  preferred_channel    TEXT,
  preferred_language   TEXT,
  tags                 TEXT,
  -- optional anonymous id supplied in the CSV → lets manual membership stitch to
  -- an anonymous web profile (one of the customer-mapping sources).
  anonymous_id         TEXT,
  capsuite_ref         TEXT,
  synced_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, member_id)
);
CREATE INDEX manual_membership_email_idx ON manual.membership(company_id, LOWER(primary_email)) WHERE primary_email IS NOT NULL;
CREATE INDEX manual_membership_phone_idx ON manual.membership(company_id, primary_phone) WHERE primary_phone IS NOT NULL;
CREATE INDEX manual_membership_anon_idx  ON manual.membership(company_id, anonymous_id) WHERE anonymous_id IS NOT NULL;

-- ── Sale order header (manual upload) ───────────────────────────────────────
CREATE TABLE manual.sale (
  trxn_id                    TEXT        NOT NULL,
  company_id                 UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  upload_batch_id            UUID        REFERENCES manual.upload_batches(id) ON DELETE SET NULL,
  is_manual                  BOOLEAN     NOT NULL DEFAULT true,
  member_id                  TEXT,
  trxn_ref                   TEXT,
  trxn_channel               TEXT        DEFAULT 'manual',
  trxn_date                  TIMESTAMPTZ,
  trxn_original_net_amt      NUMERIC,
  trxn_original_net_currency TEXT,
  trxn_order_status          TEXT,                       -- draft | confirmed | completed | cancelled
  subsidiary_name            TEXT,
  remark                     TEXT,
  capsuite_ref               TEXT,
  synced_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, trxn_id)
);
CREATE INDEX manual_sale_member_idx ON manual.sale(company_id, member_id);
CREATE INDEX manual_sale_date_idx   ON manual.sale(company_id, trxn_date);

-- ── Sale order line items (manual upload) ───────────────────────────────────
CREATE TABLE manual.sale_order_line (
  trxn_item_id              TEXT        NOT NULL,
  company_id                UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  trxn_id                   TEXT        NOT NULL,
  member_id                 TEXT,
  trxn_item_qty             INTEGER,
  trxn_item_net_unit_price  NUMERIC,
  trxn_item_discount_amt    NUMERIC,
  trxn_date                 TIMESTAMPTZ,
  prod_id                   TEXT,
  prod_sku                  TEXT,
  prod_category             TEXT,
  prod_name                 TEXT,
  capsuite_ref              TEXT,
  synced_at                 TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, trxn_item_id),
  FOREIGN KEY (company_id, trxn_id) REFERENCES manual.sale(company_id, trxn_id) ON DELETE CASCADE
);
CREATE INDEX manual_sol_trxn_idx ON manual.sale_order_line(company_id, trxn_id);
CREATE INDEX manual_sol_prod_idx ON manual.sale_order_line(company_id, prod_id);

-- ── Products (manual upload) ────────────────────────────────────────────────
CREATE TABLE manual.product (
  prod_id         TEXT        NOT NULL,
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  upload_batch_id UUID        REFERENCES manual.upload_batches(id) ON DELETE SET NULL,
  is_manual       BOOLEAN     NOT NULL DEFAULT true,
  prod_sku        TEXT,
  prod_name       TEXT,
  prod_category   TEXT,
  prod_type       TEXT,
  prod_price      NUMERIC,
  tags            TEXT,
  capsuite_ref    TEXT,
  synced_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, prod_id)
);
CREATE INDEX manual_product_sku_idx ON manual.product(company_id, prod_sku);


-- ========================= 09_ga_landing.sql =========================

-- ============================================================================
--  09_ga_landing.sql - Google Analytics + Google Search Console data source
-- ----------------------------------------------------------------------------
--  Landing zone for the GA4 / GSC pipelines, now COMPANY-SCOPED (was a single
--  global capsuite_ref). The external Airflow DAGs map capsuite_ref → company_id
--  via app.companies and write company_id on every row. Anonymous web activity
--  here (captured via the interaction-service tracker) feeds app.anonymous_profiles.
--
--  Every table keeps capsuite_ref for pipeline compatibility but company_id is
--  the authoritative tenant key.
-- ============================================================================

-- ── Event-level navigation log (the core behavioral table) ──────────────────
CREATE TABLE ga_landing.path_exploration (
  id                    BIGINT      GENERATED ALWAYS AS IDENTITY,
  company_id            UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  event_name            TEXT,
  date_hour_minute      TIMESTAMP,                 -- naive, GA property tz
  date                  TEXT,                      -- YYYYMMDD partition key
  page_referrer         TEXT,
  page_location         TEXT,
  link_url              TEXT,
  session_source_medium TEXT,
  session_campaign_name TEXT,
  capsuite_sid          TEXT,                      -- session id
  capsuite_uid          TEXT,                      -- user id
  capsuite_apid         TEXT,                      -- anonymous/visitor id
  capsuite_identifier   TEXT,
  capsuite_ref          TEXT,
  property_id           TEXT,
  property_name         TEXT,
  synced_at             TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, id)
);
CREATE INDEX gal_pe_company_apid_idx ON ga_landing.path_exploration(company_id, capsuite_apid);
CREATE INDEX gal_pe_company_date_idx ON ga_landing.path_exploration(company_id, date);
CREATE INDEX gal_pe_company_event_idx ON ga_landing.path_exploration(company_id, event_name);
-- profile-mapping: capsuite_uid lookup (logged-in visitor -> known member)
CREATE INDEX gal_pe_company_uid_idx ON ga_landing.path_exploration(company_id, capsuite_uid);

-- ── Same, with engagement duration (dwell-time analysis) ────────────────────
CREATE TABLE ga_landing.path_exploration_duration (
  id                       BIGINT      GENERATED ALWAYS AS IDENTITY,
  company_id               UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  event_name               TEXT,
  date_hour_minute         TIMESTAMP,
  date                     TEXT,
  page_referrer            TEXT,
  page_location            TEXT,
  session_source_medium    TEXT,
  user_engagement_duration INTEGER,
  capsuite_sid             TEXT,
  capsuite_uid             TEXT,
  capsuite_apid            TEXT,
  capsuite_identifier      TEXT,
  capsuite_ref             TEXT,
  property_id              TEXT,
  property_name            TEXT,
  synced_at                TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, id)
);
CREATE INDEX gal_ped_company_date_idx ON ga_landing.path_exploration_duration(company_id, date);

-- ── Outbound-link clicks (event_name = 'click', external link_url) ───────────
--  Same event grain as path_exploration; written by the GA path/outbound DAG.
CREATE TABLE ga_landing.outbound_links_attributes (
  id               BIGINT      GENERATED ALWAYS AS IDENTITY,
