-- ── Event catalog ───────────────────────────────────────────────────────────
CREATE TABLE ga_landing.event_list (
  id            BIGINT      GENERATED ALWAYS AS IDENTITY,
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  date          TEXT,
  event_name    TEXT,
