  clicks              REAL,
  impressions         REAL,
  ctr                 REAL,
  position            REAL,
  rank_by_impressions INTEGER,
  rank_by_clicks      INTEGER,
  capsuite_ref        TEXT,
  synced_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, id)
);
CREATE INDEX gal_kw_company_date_idx ON ga_landing.keyword_performance(company_id, date);

-- ── Monthly conversion funnel (Session → Page view → Scroll → Purchase) ──────
--  Partitioned monthly by tracking_period ('YYYY-MM'); two breakdowns per month
--  (tracking_type = 'source_medium' | 'campaign'). Written by the path_funnel DAG.
CREATE TABLE ga_landing.funnel_report (
  id                           BIGINT      GENERATED ALWAYS AS IDENTITY,
  company_id                   UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  funnel_step                  TEXT,
  funnel_step_name             TEXT,
  session_source               TEXT,
  session_medium               TEXT,
  session_campaign             TEXT,
  active_users                 INTEGER,
  funnel_step_completion_rate  REAL,
  funnel_step_abandonments     INTEGER,
  funnel_step_abandonment_rate REAL,
  tracking_type                TEXT,       -- 'source_medium' | 'campaign'
  tracking_period              TEXT,       -- 'YYYY-MM' monthly partition key
  capsuite_ref                 TEXT,
  property_id                  TEXT,
  property_name                TEXT,
  synced_at                    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, id)
);
CREATE INDEX gal_fr_company_period_idx ON ga_landing.funnel_report(company_id, tracking_period);

-- ── Purchase transactions (event_name = 'purchase', identity-stamped) ────────
--  Partitioned by date (YYYYMMDD). Written by the purchase DAG; feeds profile
--  identity resolution via the capsuite_* ids.
CREATE TABLE ga_landing.purchase_list (
  id                  BIGINT      GENERATED ALWAYS AS IDENTITY,
  company_id          UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  date                TEXT,       -- YYYYMMDD partition key
  trxn_id             TEXT,
  capsuite_sid        TEXT,
  capsuite_apid       TEXT,
  capsuite_uid        TEXT,
  capsuite_identifier TEXT,
  capsuite_ref        TEXT,
  property_id         TEXT,
  property_name       TEXT,
  synced_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, id)
);
CREATE INDEX gal_pl_company_date_idx ON ga_landing.purchase_list(company_id, date);
-- profile-mapping: trxn_id lookup (GA purchase -> commerce/manual order -> buyer)
CREATE INDEX gal_pl_company_trxn_idx ON ga_landing.purchase_list(company_id, trxn_id);

-- ── Sync control / incremental watermark (one row per workspace × report) ────
--  The DAGs read this BEFORE each fetch to decide the start date, and advance
--  last_sync_date in the SAME transaction as the data load (idempotent re-runs).
--  Resume logic (see dags/click_cdp_ai/lib/pg_state.py):
--    is_debugging = TRUE  -> 1st of (today - debug_months)
--    last_sync_date set   -> last_sync_date - overlap_days   (daily incremental)
--    first run            -> plan-based backfill: 3y free/trial, 5y pro/enterprise
--  Keyed by capsuite_ref (1:1 with a workspace) so the external ETL stays
--  decoupled from app UUIDs. Created here so the schema is authoritative; the
--  DAG also ensures it at runtime (CREATE IF NOT EXISTS) for safety.
CREATE TABLE ga_landing.ga_sync_control (
  capsuite_ref   TEXT        NOT NULL,
  report         TEXT        NOT NULL,
  is_debugging   BOOLEAN     NOT NULL DEFAULT FALSE,
  debug_months   INTEGER     NOT NULL DEFAULT 2,
  overlap_days   INTEGER     NOT NULL DEFAULT 7,
  last_sync_date DATE,
  last_run_at    TIMESTAMPTZ,
  last_status    TEXT,
  error_message  TEXT,
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (capsuite_ref, report)
);


-- ========================= 10_shopify.sql =========================

-- ============================================================================
--  10_shopify.sql - Shopify RAW landing (schema: shopify), COMPANY-SCOPED
-- ----------------------------------------------------------------------------
--  Raw, Shopify-NATIVE data synced by the click_cdp_ai Shopify DAGs
--  (dags/click_cdp_ai/shopify/* via lib/shopify_transforms + lib/pg_loader).
--  Column sets AND scalar types mirror the DAG transforms 1:1: pg_loader infers
--  raw landing types from the pandas DataFrame, so money / amounts and the raw
--  created_at land as TEXT and counts as BIGINT here. Cross-platform
--  normalization + casting to numeric/timestamptz/boolean deliberately does NOT
--  happen here - it happens in the neutral commerce.* layer (14_commerce.sql),
--  which is what the app / profile builder / AI analyst read. Keep these types
--  matching pg_loader._pg_type_for_series or inserts will fail the type cast.
--
--  ID convention: {capsuite_ref}_{entity}_{shopifyNativeId}, e.g.
--  acme_order_123, acme_cust_456, acme_product_789 (variant grain),
--  acme_orderline_321, acme_refund_654.
--
--  Every table is keyed by (company_id, <natural key>). pg_loader stamps
--  company_id (resolved from app.companies by capsuite_ref) on every row and
--  replaces scoped by (company_id, key-values-present) - delete-then-insert,
--  so no ON CONFLICT clauses are needed.
--
--  The per-(client, dataset) incremental watermark lives in
--  shopify.shopify_sync_control (created here to mirror lib/pg_state).
-- ============================================================================

-- ── Customers ────────────────────────────────────────────────────────────────
CREATE TABLE shopify.customer (
  customer_id     TEXT        NOT NULL,
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  created_at      TEXT,                       -- raw Shopify string (commerce.* casts)
  updated_at      TIMESTAMPTZ,
  email           TEXT,
  phone           TEXT,                       -- normalized, '+' stripped
  first_name      TEXT,
  last_name       TEXT,
  full_name       TEXT,
  is_opt_in_email TEXT,                       -- 'true'/'false' string from transform
  is_opt_in_sms   TEXT,
  tags            TEXT,
  capsuite_ref    TEXT,
  PRIMARY KEY (company_id, customer_id)
);
CREATE INDEX shopify_customer_email_idx ON shopify.customer(company_id, LOWER(email)) WHERE email IS NOT NULL;
CREATE INDEX shopify_customer_ref_idx   ON shopify.customer(capsuite_ref);

-- ── Orders (header) ──────────────────────────────────────────────────────────
CREATE TABLE shopify."order" (
  order_id           TEXT        NOT NULL,
  company_id         UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  customer_id        TEXT,
  order_name         TEXT,                    -- Shopify order name, e.g. "#1001"
  created_at         TEXT,                    -- raw Shopify string (commerce.* casts)
  total_price        TEXT,
  currency           TEXT,
  total_refunded     TEXT,
  net_payment        TEXT,
  financial_status   TEXT,                    -- PAID | PARTIALLY_REFUNDED | REFUNDED | VOIDED | ...
  fulfillment_status TEXT,                    -- FULFILLED | IN_PROGRESS | RESTOCKED | ...
  capsuite_ref       TEXT,
  PRIMARY KEY (company_id, order_id)
);
CREATE INDEX shopify_order_customer_idx ON shopify."order"(company_id, customer_id);
CREATE INDEX shopify_order_ref_idx      ON shopify."order"(capsuite_ref);

-- ── Order lines (line items + shipping lines) ────────────────────────────────
CREATE TABLE shopify.order_line (
  order_line_id         TEXT        NOT NULL,
  company_id            UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  order_id              TEXT,
  line_type             TEXT,                 -- line_item | shipping
  product_id            TEXT,                 -- variant grain ({ref}_product_{variantId})
  product_sku           TEXT,
  product_name          TEXT,
  quantity_ordered      BIGINT,
  quantity_current      BIGINT,               -- after removals/refunds
  original_unit_price   TEXT,
  discounted_unit_price TEXT,
  currency              TEXT,
  created_at            TEXT,                 -- order created_at string (joined in transform)
  capsuite_ref          TEXT,
  PRIMARY KEY (company_id, order_line_id)
);
CREATE INDEX shopify_order_line_order_idx ON shopify.order_line(company_id, order_id);
CREATE INDEX shopify_order_line_ref_idx   ON shopify.order_line(capsuite_ref);

-- ── Product master (one row per VARIANT) ─────────────────────────────────────
CREATE TABLE shopify.product (
  product_id        TEXT        NOT NULL,     -- {ref}_product_{variantId}
  company_id        UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  product_temp_id   TEXT,
  product_sku       TEXT,
  price             TEXT,
  product_name      TEXT,                     -- "Product - Variant" when variant-titled
  product_type      TEXT,
  taxonomy_category TEXT,                     -- Shopify taxonomy node name
  tags              TEXT,
  created_at        TEXT,                     -- raw Shopify string (commerce.* casts)
  updated_at        TIMESTAMPTZ,
  capsuite_ref      TEXT,
  PRIMARY KEY (company_id, product_id)
);
CREATE INDEX shopify_product_sku_idx ON shopify.product(company_id, product_sku);
CREATE INDEX shopify_product_ref_idx ON shopify.product(capsuite_ref);

-- ── Product custom attributes (collection memberships) ───────────────────────
CREATE TABLE shopify.product_detail (
  company_id       UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  product_id       TEXT        NOT NULL,
  custom_attribute TEXT        NOT NULL,      -- e.g. 'collection'
  custom_value     TEXT        NOT NULL,
  capsuite_ref     TEXT,
  PRIMARY KEY (company_id, product_id, custom_attribute, custom_value)
);
CREATE INDEX shopify_product_detail_ref_idx ON shopify.product_detail(capsuite_ref);

-- ── Product images (featured image per variant) ──────────────────────────────
CREATE TABLE shopify.product_image (
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  product_id      TEXT        NOT NULL,
  product_sku     TEXT,
  product_handle  TEXT,
  product_img_id  TEXT,
  product_img_url TEXT,
  created_at      TEXT,                       -- raw Shopify string (commerce.* casts)
  updated_at      TIMESTAMPTZ,
  capsuite_ref    TEXT,
  PRIMARY KEY (company_id, product_id)
);
CREATE INDEX shopify_product_image_sku_idx ON shopify.product_image(company_id, product_sku);
CREATE INDEX shopify_product_image_ref_idx ON shopify.product_image(capsuite_ref);

-- ── Inventory levels (FULL snapshot - replaced per client on every run) ──────
CREATE TABLE shopify.inventory_level (
  company_id         UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  inventory_level_id BIGINT,                  -- synthetic per-snapshot row number
  product_id         TEXT        NOT NULL,    -- variant grain
  location_id        TEXT        NOT NULL,
  quantity           BIGINT,
  updated_at         TIMESTAMPTZ,
  capsuite_ref       TEXT,
  PRIMARY KEY (company_id, product_id, location_id)
);
CREATE INDEX shopify_inventory_level_ref_idx ON shopify.inventory_level(capsuite_ref);

-- ── Refunds (order-level summary) ────────────────────────────────────────────
CREATE TABLE shopify.refund (
  refund_id       TEXT        NOT NULL,
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  order_id        TEXT,
  refund_date     TEXT,                       -- raw Shopify string (commerce.* casts)
  refund_amount   TEXT,
  refund_currency TEXT,
  note            TEXT,
  capsuite_ref    TEXT,
  PRIMARY KEY (company_id, refund_id)
);
CREATE INDEX shopify_refund_order_idx ON shopify.refund(company_id, order_id);
CREATE INDEX shopify_refund_ref_idx   ON shopify.refund(capsuite_ref);

-- ── Refund line items ────────────────────────────────────────────────────────
CREATE TABLE shopify.refund_line (
  refund_line_id  TEXT        NOT NULL,
  company_id      UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  refund_id       TEXT,
  order_id        TEXT,
  order_line_id   TEXT,
  product_id      TEXT,
  product_sku     TEXT,
  refunded_qty    BIGINT,
  refund_subtotal TEXT,
  refund_currency TEXT,
  restock_type    TEXT,                       -- RETURN | CANCEL | NO_RESTOCK | LEGACY_RESTOCK
  capsuite_ref    TEXT,
  PRIMARY KEY (company_id, refund_line_id)
);
CREATE INDEX shopify_refund_line_refund_idx ON shopify.refund_line(company_id, refund_id);
CREATE INDEX shopify_refund_line_ref_idx    ON shopify.refund_line(capsuite_ref);

-- ── Incremental sync control (mirrors dags lib/pg_state.ensure_control_table) ─
CREATE TABLE shopify.shopify_sync_control (
  capsuite_ref   TEXT        NOT NULL,
  report         TEXT        NOT NULL,        -- dataset name (order, customer, refund, ...)
  is_debugging   BOOLEAN     NOT NULL DEFAULT FALSE,
  debug_months   INTEGER     NOT NULL DEFAULT 2,
  overlap_days   INTEGER     NOT NULL DEFAULT 7,
  last_sync_date DATE,
  last_run_at    TIMESTAMPTZ,
  last_status    TEXT,
  error_message  TEXT,
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (capsuite_ref, report)
);


-- ========================= 11_interaction.sql =========================

-- ============================================================================
--  11_interaction.sql - SHARED schema for the interaction-service microservice
-- ----------------------------------------------------------------------------
--  The interaction-service is a separate Go/GORM microservice (models: Company,
--  Interaction, Activity, Customer). It connects to THIS database and reads/writes
--  the `interaction` schema directly (GORM NamingStrategy TablePrefix "interaction.",
--  AutoMigrate DISABLED). Therefore the column names and types below MUST match the
--  GORM models exactly — this file is the single source of truth for the schema.
--
--  GORM conventions assumed:
--    - BaseModel → id UUID (gen_random_uuid), created_at, updated_at
--    - struct fields → snake_case columns
--  Popup analytics in server/routes/popup.js join these tables locally:
--    interaction.companies(id, cdp_company_id)
--    interaction.interactions(id, company_id → companies.id, cdp_reference_id)
--    interaction.activities(correlated_interaction_id → interactions.id,
--                           capsuite_sid, action, created_at)
--  Workspace deletes cascade in via interaction.companies.cdp_company_id.
-- ============================================================================

-- ── Companies (service company ↔ app workspace) ─────────────────────────────
--  GORM model: Company{ ID, CreatedAt, UpdatedAt, Name, CdpCompanyId(uniqueIndex) }
CREATE TABLE interaction.companies (
  id             UUID        PRIMARY KEY DEFAULT gen_random_uuid(),  -- interaction-service company id
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  name           TEXT,
  cdp_company_id UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,  -- → app workspace
  synced_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE UNIQUE INDEX interaction_companies_cdp_idx ON interaction.companies(cdp_company_id);

-- ── Interactions (popup definitions served by the microservice) ─────────────
--  GORM model: Interaction{ ID, CreatedAt, UpdatedAt, Name, CompanyID,
--    InteractionType, CdpReferenceId(uniqueIndex), Rules(jsonb), Content,
--    DefaultRecommendation(jsonb), IsActive, StartTime, EndTime, IsDefault }
CREATE TABLE interaction.interactions (
  id                     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at             TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at             TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  name                   TEXT        NOT NULL DEFAULT '',
  company_id             UUID        NOT NULL REFERENCES interaction.companies(id) ON DELETE CASCADE,
  interaction_type       TEXT,
  cdp_reference_id       TEXT,                              -- ↔ app.popups.cdp_reference_id
  rules                  JSONB       NOT NULL DEFAULT '{}',
  content                TEXT,
  default_recommendation JSONB       NOT NULL DEFAULT '{}',
  is_active              BOOLEAN     NOT NULL DEFAULT false,
  start_time             TIMESTAMPTZ,
  end_time               TIMESTAMPTZ,
  is_default             BOOLEAN     NOT NULL DEFAULT false,
  status                 TEXT,                              -- extra: convenience mirror of app.popups.status
  synced_at              TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE UNIQUE INDEX interaction_interactions_ref_idx  ON interaction.interactions(cdp_reference_id);
CREATE INDEX interaction_interactions_company_idx     ON interaction.interactions(company_id);

-- ── Activities (impressions/clicks/closes/email collection) ─────────────────
--  GORM model: Activity{ ID, CreatedAt, UpdatedAt, CapsuiteSid, CapsuiteApid,
--    Action, CorrelatedInteractionId, UrlParameters, JsonParameters }
--  action ∈ visit | retrieve_interaction | click_interaction | close_interaction | email_collection
--  Captured form fields (e.g. the collected email) live as JSON in json_parameters.
CREATE TABLE interaction.activities (
  id                        UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at                TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at                TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  capsuite_sid              TEXT,       -- session id
  capsuite_apid             TEXT,       -- anonymous/visitor id
  action                    TEXT        NOT NULL,
  correlated_interaction_id UUID        REFERENCES interaction.interactions(id) ON DELETE CASCADE,
  url_parameters            TEXT,       -- raw query-string params (debug)
  json_parameters           TEXT,       -- JSON payload: { email, link_url, post_url, ... }
  page_url                  TEXT,       -- extra (seed/reporting convenience)
  page_title                TEXT,       -- extra (seed/reporting convenience)
  synced_at                 TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX interaction_activities_corr_idx   ON interaction.activities(correlated_interaction_id);
CREATE INDEX interaction_activities_action_idx ON interaction.activities(action, created_at DESC);
CREATE INDEX interaction_activities_sid_idx    ON interaction.activities(capsuite_sid);

-- ── Customers (per-visitor recommendation overrides; rarely used) ────────────
--  GORM model: Customer{ ID, CreatedAt, UpdatedAt, Recommendations(text[]),
--    CapsuiteSid(primaryKey), InteractionID }. Extra columns below support the
--  dev seed's email-lead demo data and are ignored by the service.
CREATE TABLE interaction.customers (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  recommendations TEXT[],
  capsuite_sid  TEXT,
  interaction_id UUID,
  company_id    UUID        REFERENCES interaction.companies(id) ON DELETE CASCADE,  -- extra (seed)
  capsuite_apid TEXT,                                                                -- extra (seed)
  email         TEXT,                                                                -- extra (seed)
  first_name    TEXT,                                                                -- extra (seed)
  last_name     TEXT,                                                                -- extra (seed)
  synced_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX interaction_customers_email_idx ON interaction.customers(company_id, LOWER(email)) WHERE email IS NOT NULL;

-- ── Project collected emails into app.popup_email_collected ─────────────────
--  When the microservice records an `email_collection` activity, surface it as a
--  lead row on app.popup_email_collected (what the "Emails Collected" tab and the
--  create-profile flow read). The collected fields come from the activity's
--  json_parameters JSON blob (see buildJsonParameters in the Go service):
--    { email, first_name, last_name, phone, post_url, page_title, utm_* }
--  Deduped to one row per (workspace, popup, email).
CREATE OR REPLACE FUNCTION interaction.project_email_collection() RETURNS trigger AS $$
DECLARE
  v_json        jsonb;
  v_email       text;
  v_ref         text;
  v_cdp_company uuid;
  v_popup       app.popups%ROWTYPE;
BEGIN
  -- json_parameters is TEXT holding a JSON object; tolerate malformed payloads.
  BEGIN
    v_json := NEW.json_parameters::jsonb;
  EXCEPTION WHEN others THEN
    v_json := '{}'::jsonb;
  END;

  v_email := NULLIF(btrim(lower(v_json->>'email')), '');
  IF v_email IS NULL THEN
    RETURN NEW;  -- no email captured on this submit
  END IF;

  -- Resolve the owning popup: activity → interaction → service company → workspace.
  SELECT i.cdp_reference_id, c.cdp_company_id
    INTO v_ref, v_cdp_company
    FROM interaction.interactions i
    JOIN interaction.companies c ON c.id = i.company_id
   WHERE i.id = NEW.correlated_interaction_id;

  IF v_cdp_company IS NULL THEN
    RETURN NEW;  -- orphan activity, cannot attribute to a workspace
  END IF;

  SELECT * INTO v_popup
    FROM app.popups
   WHERE company_id = v_cdp_company AND cdp_reference_id = v_ref
   LIMIT 1;

  -- Dedupe: one lead row per (workspace, popup, email).
  IF EXISTS (
    SELECT 1 FROM app.popup_email_collected
     WHERE company_id = v_cdp_company
       AND lower(email) = v_email
       AND popup_ref IS NOT DISTINCT FROM v_ref
  ) THEN
    RETURN NEW;
  END IF;

  INSERT INTO app.popup_email_collected (
    collected_at, company_id, popup_id, popup_name, popup_ref,
    email, first_name, last_name, phone,
    source_url, page_title, visitor_id, session_id,
    utm_source, utm_medium, utm_campaign, utm_term, utm_content,
    metadata
  ) VALUES (
    NEW.created_at, v_cdp_company, v_popup.id, v_popup.name, v_ref,
    v_email,
    NULLIF(v_json->>'first_name',''), NULLIF(v_json->>'last_name',''), NULLIF(v_json->>'phone',''),
    COALESCE(NULLIF(v_json->>'post_url',''), NULLIF(v_json->>'source_url','')),
    NULLIF(v_json->>'page_title',''),
    NEW.capsuite_apid, NEW.capsuite_sid,
    NULLIF(v_json->>'utm_source',''), NULLIF(v_json->>'utm_medium',''), NULLIF(v_json->>'utm_campaign',''),
    NULLIF(v_json->>'utm_term',''), NULLIF(v_json->>'utm_content',''),
    jsonb_build_object('source','interaction_activity','activity_id', NEW.id)
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS activities_project_email ON interaction.activities;
CREATE TRIGGER activities_project_email
  AFTER INSERT ON interaction.activities
  FOR EACH ROW
  WHEN (NEW.action = 'email_collection')
  EXECUTE FUNCTION interaction.project_email_collection();

-- ── Sync bookkeeping (vestigial: kept for compatibility; no ETL in unified mode) ─
CREATE TABLE interaction.sync_state (
  company_id     UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  entity         TEXT        NOT NULL,   -- interactions | activities | customers
  last_synced_at TIMESTAMPTZ,
  last_cursor    TEXT,
  status         TEXT        NOT NULL DEFAULT 'idle',
  error_message  TEXT,
  updated_date   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (company_id, entity)
);


-- ========================= 12_profiles_identity.sql =========================

-- ============================================================================
--  12_profiles_identity.sql - UNIFIED customer profiles + identity map
-- ----------------------------------------------------------------------------
--  The master person list and the mapping layer that stitches together
--  membership from every source (manual, shopify) plus web identity (GA
--  anonymous ids, popup-collected emails).
--
--        app.customer_profiles      ← golden record, one per resolved person/company
--                ▲
--                │ app.profile_identities  (the identity graph)
--                │
--   ┌────────────┼───────────────┬──────────────────┬───────────────────────┐
--  manual.membership   shopify.membership   ga_landing (anonymous_id)   interaction.customers
--                                                                        (collected email)
--
--  app.anonymous_profiles holds visitors not yet resolved to a customer; when an
--  identity link appears (email capture / manual mapping with anonymous_id) the
--  anonymous row is linked to a customer profile via app.profile_identities.
-- ============================================================================

-- ── Master customer profile (golden record) ────────────────────────────────
-- member_id is the resolved person key, unique per company. member_source tells
-- where the primary record came from; 'mixed' when stitched from >1 source.
CREATE TABLE app.customer_profiles (
  company_id            UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  member_id             TEXT        NOT NULL,
  created_date          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  member_source         TEXT        NOT NULL DEFAULT 'manual',  -- manual | shopify | ga | mixed
  capsuite_ref          TEXT,
  -- identity
  primary_email         TEXT,
  secondary_email       TEXT,
  eng_full_name         TEXT,
  eng_first_name        TEXT,
  eng_last_name         TEXT,
  chi_full_name         TEXT,
  display_name          TEXT,
  member_no             TEXT,
  title                 TEXT,
  -- membership
  member_join_date      TIMESTAMPTZ,
  member_last_update    TIMESTAMPTZ,
  member_reg_channel    TEXT,
  member_reg_location   TEXT,
  member_type           TEXT,
  is_company            BOOLEAN,
  -- demographics
  gender                TEXT,
  age                   TEXT,
  age_group             TEXT,
  birthday_year         TEXT,
  birthday_month        TEXT,
  birthday_day          TEXT,
  education_level       TEXT,
  income_level          TEXT,
  employment_status     TEXT,
  marital_status        TEXT,
  nationality           TEXT,
  -- contact & preferences (booleans are native BOOLEAN now, not TEXT)
  has_email             BOOLEAN,
  has_phone             BOOLEAN,
  primary_phone         TEXT,
  preferred_language    TEXT,
  preferred_channel     TEXT,
  is_opt_in_email       BOOLEAN,
  is_opt_in_call        BOOLEAN,
  is_opt_in_dm          BOOLEAN,
  is_opt_in_sms         BOOLEAN,
  is_subscriber_only    BOOLEAN,
  tags                  TEXT,
  -- GA web activity (aggregated; display cache)
  ga_sessions           INTEGER     DEFAULT 0,
  ga_total_events       INTEGER     DEFAULT 0,
  ga_page_views         INTEGER     DEFAULT 0,
  ga_first_visits       INTEGER     DEFAULT 0,
  ga_form_starts        INTEGER     DEFAULT 0,
  ga_form_completes     INTEGER     DEFAULT 0,
  ga_scroll_events      INTEGER     DEFAULT 0,
  ga_whatsapp_clicks    INTEGER     DEFAULT 0,
  ga_file_downloads     INTEGER     DEFAULT 0,
  ga_first_seen         DATE,
  ga_last_seen          DATE,
  ga_top_source_medium  TEXT,
  ga_top_campaign       TEXT,
  ga_visitor_ids        TEXT[]      DEFAULT '{}',
  ga_source_mediums     TEXT[]      DEFAULT '{}',
  ga_campaigns          TEXT[]      DEFAULT '{}',
  ga_events_list        TEXT[]      DEFAULT '{}',
  ga_pages_visited      TEXT[]      DEFAULT '{}',
  -- commerce (aggregated from manual/shopify sales; display cache)
  order_count           INTEGER     DEFAULT 0,
  total_spend           NUMERIC     DEFAULT 0,
  first_order_date      TIMESTAMPTZ,
  last_order_date       TIMESTAMPTZ,
  -- offline / CRM activity
  seminar_count         INTEGER     DEFAULT 0,
  seminars              JSONB       DEFAULT '[]',
  -- attributes (display cache; source of truth = app.profile_attribute_values)
  attribute_count       INTEGER     DEFAULT 0,
  attributes            JSONB       DEFAULT '{}',
  -- provenance
  is_manual             BOOLEAN     NOT NULL DEFAULT false,
  last_refreshed        TIMESTAMPTZ DEFAULT NOW(),
  PRIMARY KEY (company_id, member_id)
);
CREATE INDEX customer_profiles_company_email_idx ON app.customer_profiles(company_id, LOWER(primary_email)) WHERE primary_email IS NOT NULL;
CREATE INDEX customer_profiles_company_phone_idx ON app.customer_profiles(company_id, primary_phone) WHERE primary_phone IS NOT NULL;
CREATE INDEX customer_profiles_source_idx        ON app.customer_profiles(company_id, member_source);
CREATE TRIGGER customer_profiles_updated_date BEFORE UPDATE ON app.customer_profiles
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Identity map (the mapping layer to every source) ────────────────────────
-- Each row links a master profile to one contributing identity. A profile can
-- have many identities (an email, a phone, a shopify member_id, several GA
-- anonymous ids). identity_value is unique per (company, identity_type) so the
-- same email/anonymous id can't point at two profiles in one workspace.
CREATE TABLE app.profile_identities (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  member_id     TEXT        NOT NULL,                 -- → app.customer_profiles.member_id (same company)
  source        TEXT        NOT NULL,                 -- manual | shopify | ga | interaction | popup
  source_id     TEXT,                                 -- natural key in the source table (e.g. shopify member_id, trxn customerId)
  identity_type TEXT        NOT NULL CHECK (identity_type IN ('email','phone','member_id','anonymous_id')),
  identity_value TEXT       NOT NULL,
  is_primary    BOOLEAN     NOT NULL DEFAULT false,
  first_seen    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  last_seen     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  metadata      JSONB       NOT NULL DEFAULT '{}',
  FOREIGN KEY (company_id, member_id) REFERENCES app.customer_profiles(company_id, member_id) ON DELETE CASCADE
);
CREATE UNIQUE INDEX profile_identities_unique_idx
  ON app.profile_identities(company_id, identity_type, LOWER(identity_value));
CREATE INDEX profile_identities_member_idx ON app.profile_identities(company_id, member_id);
CREATE INDEX profile_identities_source_idx ON app.profile_identities(company_id, source, source_id);
CREATE TRIGGER profile_identities_updated_date BEFORE UPDATE ON app.profile_identities
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();

-- ── Anonymous visitor profiles (unresolved web visitors) ────────────────────
-- Built from ga_landing.path_exploration (and interaction.activities) for
-- visitors not yet linked to a customer profile. resolved_member_id is set when
-- an identity link is found (email capture / manual anonymous_id mapping).
CREATE TABLE app.anonymous_profiles (
  company_id          UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  visitor_id          TEXT        NOT NULL,           -- capsuite_apid
  first_seen          DATE,
  last_seen           DATE,
  total_events        INTEGER     DEFAULT 0,
  page_views          INTEGER     DEFAULT 0,
  sessions            INTEGER     DEFAULT 0,
  first_visits        INTEGER     DEFAULT 0,
  form_starts         INTEGER     DEFAULT 0,
  form_completes      INTEGER     DEFAULT 0,
  scroll_events       INTEGER     DEFAULT 0,
  whatsapp_clicks     INTEGER     DEFAULT 0,
  file_downloads      INTEGER     DEFAULT 0,
  click_events        INTEGER     DEFAULT 0,
  user_engagement     INTEGER     DEFAULT 0,
  top_source_medium   TEXT,
  top_campaign        TEXT,
  source_mediums      TEXT[]      DEFAULT '{}',
  campaigns           TEXT[]      DEFAULT '{}',
  events              TEXT[]      DEFAULT '{}',
  pages_visited       TEXT[]      DEFAULT '{}',
  -- set once stitched to a known customer (via profile_identities)
  resolved_member_id  TEXT,
  resolved_at         TIMESTAMPTZ,
  last_refreshed      TIMESTAMPTZ DEFAULT NOW(),
  PRIMARY KEY (company_id, visitor_id)
);
CREATE INDEX anonymous_profiles_resolved_idx ON app.anonymous_profiles(company_id, resolved_member_id) WHERE resolved_member_id IS NOT NULL;

-- ── Profile merge candidates (review queue for cross-source duplicates) ─────
CREATE TABLE app.profile_merge_candidates (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_date  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  company_id    UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  member_id_a   TEXT        NOT NULL,   -- existing / kept profile
  source_a      TEXT,
  member_id_b   TEXT        NOT NULL,   -- newer / incoming profile
  source_b      TEXT,
  match_type    TEXT        NOT NULL,   -- email | phone | email+phone | anonymous_id
  match_value   TEXT,
  confidence    TEXT        NOT NULL DEFAULT 'exact',   -- exact | fuzzy
  status        TEXT        NOT NULL DEFAULT 'pending', -- pending | merged | dismissed
  resolved_into TEXT,                   -- surviving member_id after a merge
  resolved_by   UUID        REFERENCES app.users(id) ON DELETE SET NULL,
  resolved_at   TIMESTAMPTZ,
  metadata      JSONB       NOT NULL DEFAULT '{}'
);
CREATE UNIQUE INDEX profile_merge_candidates_pair_idx
  ON app.profile_merge_candidates(company_id, LEAST(member_id_a, member_id_b), GREATEST(member_id_a, member_id_b), match_type);
CREATE INDEX profile_merge_candidates_status_idx ON app.profile_merge_candidates(company_id, status);
CREATE TRIGGER profile_merge_candidates_updated_date BEFORE UPDATE ON app.profile_merge_candidates
  FOR EACH ROW EXECUTE FUNCTION app.set_updated_date();


-- ========================= 13_rule_indexes.sql =========================

-- ============================================================================
-- 13_rule_indexes.sql
-- Supporting indexes for Rule-attribute relation conditions (segment / pop-up /
-- EDM / attribute / purchases). Every statement is IF NOT EXISTS so this file is
-- safe to re-run and safe to apply to a live database without a teardown.
-- ============================================================================

-- EDM: "received / opened / clicked campaign X" correlate edm_sends / edm_events
-- to a profile by member_id or LOWER(email).
CREATE INDEX IF NOT EXISTS edm_sends_member_idx        ON app.edm_sends(member_id);
CREATE INDEX IF NOT EXISTS edm_sends_lower_email_idx   ON app.edm_sends(LOWER(email));
CREATE INDEX IF NOT EXISTS edm_events_campaign_type_idx ON app.edm_events(edm_campaign_id, event_type);
CREATE INDEX IF NOT EXISTS edm_events_lower_email_idx  ON app.edm_events(LOWER(email));

-- Pop-ups: "submitted form" correlates popup_email_collected by member/email
-- (customer) or visitor_id (anonymous), scoped to a single pop-up.
CREATE INDEX IF NOT EXISTS popup_email_collected_popup_profile_idx ON app.popup_email_collected(popup_id, profile_id);
CREATE INDEX IF NOT EXISTS popup_email_collected_popup_visitor_idx ON app.popup_email_collected(popup_id, visitor_id);

-- Purchases: order count / spend / last order correlate commerce."order" by
-- customer_id = profile.member_id (see server/lib/attributeRules.js ORDER_*).
-- The supporting index (commerce_order_customer_only_idx) is defined in
-- 14_commerce.sql instead of here, because commerce."order" does not exist yet
-- at this point in the build order (14 runs after 13).

-- Attribute-value relation: EXISTS on profile_attribute_values matches by
-- (entity_type, entity_id, attribute_value_id) without a company filter
-- (attribute_value_id is already company-specific via FK).
CREATE INDEX IF NOT EXISTS profile_attr_value_entity_value_idx
  ON app.profile_attribute_values(entity_type, entity_id, attribute_value_id);

-- Pop-up "has seen / clicked" (anonymous) reads the interaction microservice
-- schema, joining interaction.activities (by capsuite_apid) to
-- interaction.interactions (by cdp_reference_id). Guarded - that schema may be
-- absent in some deployments.
DO $$
BEGIN
  IF to_regclass('interaction.activities') IS NOT NULL THEN
    CREATE INDEX IF NOT EXISTS interaction_activities_apid_idx ON interaction.activities(capsuite_apid);
  END IF;
  IF to_regclass('interaction.interactions') IS NOT NULL THEN
    CREATE INDEX IF NOT EXISTS interaction_interactions_ref_idx ON interaction.interactions(cdp_reference_id);
  END IF;
END $$;


-- ========================= 14_commerce.sql =========================

-- ============================================================================
--  14_commerce.sql - NEUTRAL commerce layer (schema: commerce), COMPANY-SCOPED
-- ----------------------------------------------------------------------------
--  The platform-neutral model that combines the per-platform raw schemas
--  (shopify / shopline / odoo - and any future platform, e.g. WooCommerce)
--  into one analysis-friendly shape. Built/refreshed by the
--  click_cdp_ai_commerce_landing DAG (dags/click_cdp_ai/lib/commerce_integration:
--  per client+platform, scoped DELETE + INSERT...SELECT, idempotent).
--
--  THIS is what the app reads for commerce: the profile builder
--  (commerce.customer -> app.customer_profiles), the Profiles page transaction
--  card (commerce."order"/order_line) and the AI analyst (all tables).
--
--  Every row carries company_id (tenant key), capsuite_ref, source_platform
--  ('shopify' | 'shopline' | 'odoo'), source_id (the platform-native id) and
--  source_extra JSONB for platform-specific richness.
--
--  DDL is mirrored by dags/click_cdp_ai/lib/commerce_schema.py (the DAG can
--  bootstrap the tables itself) - keep the two in sync.
-- ============================================================================

CREATE TABLE IF NOT EXISTS commerce.customer (
  customer_id     TEXT  PRIMARY KEY,            -- {ref}_cust_{id} (client-prefixed, globally unique)
  company_id      UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref    TEXT,
  source_platform TEXT,
  source_id       TEXT,
  customer_no     TEXT,
  join_date       TIMESTAMPTZ,
  last_update     TIMESTAMPTZ,
  customer_type   TEXT,
  is_company      BOOLEAN,
  has_email       BOOLEAN,
  primary_email   TEXT,
  has_phone       BOOLEAN,
  primary_phone   TEXT,
  first_name      TEXT,
  last_name       TEXT,
  full_name       TEXT,
  display_name    TEXT,
  is_opt_in_email BOOLEAN,
  is_opt_in_sms   BOOLEAN,
  tags            TEXT,
  source_extra    JSONB
);

CREATE TABLE IF NOT EXISTS commerce.product (
  product_id      TEXT  PRIMARY KEY,            -- variant grain
  company_id      UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref    TEXT,
  source_platform TEXT,
  source_id       TEXT,
  product_temp_id TEXT,
  product_sku     TEXT,
  price           NUMERIC,
  category        TEXT,
  product_type    TEXT,
  product_name    TEXT,
  tags            TEXT,
  created_at      TIMESTAMPTZ,
  updated_at      TIMESTAMPTZ,
  source_extra    JSONB
);

CREATE TABLE IF NOT EXISTS commerce.product_detail (
  company_id       UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref     TEXT,
  source_platform  TEXT,
  source_id        TEXT,
  product_id       TEXT,
  custom_attribute TEXT,
  custom_value     TEXT,
  source_extra     JSONB
);

CREATE TABLE IF NOT EXISTS commerce.product_image (
  company_id      UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref    TEXT,
  source_platform TEXT,
  source_id       TEXT,
  product_id      TEXT,
  product_sku     TEXT,
  product_handle  TEXT,
  product_img_id  TEXT,
  product_img_url TEXT,
  created_at      TIMESTAMPTZ,
  updated_at      TIMESTAMPTZ,
  source_extra    JSONB
);

CREATE TABLE IF NOT EXISTS commerce."order" (
  order_id           TEXT  PRIMARY KEY,
  company_id         UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref       TEXT,
  source_platform    TEXT,
  source_id          TEXT,
  customer_id        TEXT,
  order_ref          TEXT,                     -- platform order name/ref, e.g. "#1001"
  channel            TEXT,                     -- web | pos | ...
  order_date         TIMESTAMPTZ,
  order_year         INT,
  order_month        INT,
  order_day          INT,
  order_week         INT,
  net_amount         NUMERIC,
  currency           TEXT,
  exchange_rate      NUMERIC,
  order_status       TEXT,                     -- draft | confirmed | completed | cancelled (unified)
  total_refunded_amt NUMERIC,
  net_payment_amt    NUMERIC,
  remark             TEXT,
  source_extra       JSONB
);

CREATE TABLE IF NOT EXISTS commerce.order_line (
  order_line_id    TEXT  PRIMARY KEY,
  company_id       UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref     TEXT,
  source_platform  TEXT,
  source_id        TEXT,
  order_id         TEXT,
  customer_id      TEXT,
  order_date       TIMESTAMPTZ,
  line_type        TEXT,                       -- line_item | shipping
  product_id       TEXT,
  product_sku      TEXT,
  product_name     TEXT,
  product_type     TEXT,
  qty              NUMERIC,                    -- current quantity
  qty_ordered      NUMERIC,
  refunded_qty     NUMERIC,
  unit_price_net   NUMERIC,                    -- discounted
  unit_price_gross NUMERIC,                    -- original
  discount_amt     NUMERIC,
  currency         TEXT,
  channel          TEXT,
  bundle_id        TEXT,
  bundle_name      TEXT,
  remark           TEXT,
  source_extra     JSONB
);

CREATE TABLE IF NOT EXISTS commerce.inventory_level (
  inventory_level_id TEXT  PRIMARY KEY,        -- {product_id}_{location_id}
  company_id         UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  capsuite_ref       TEXT,
  source_platform    TEXT,
  source_id          TEXT,
  product_id         TEXT,
  location_id        TEXT,
  quantity           NUMERIC,
  quantity_reserved  NUMERIC,
  snapshot_date      TIMESTAMPTZ,
  source_extra       JSONB
);

CREATE TABLE IF NOT EXISTS commerce.refund (
  refund_id       TEXT  PRIMARY KEY,
  company_id      UUID  NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
