-- ===================== migrations/2026-06-30_interaction_schema_unify.sql =====================

-- 2026-06-30  Unify interaction-service onto the shared CDP database.
-- ----------------------------------------------------------------------------
-- The interaction-service microservice now connects to THIS database and
-- reads/writes the `interaction` schema directly (GORM TablePrefix "interaction.",
-- AutoMigrate disabled). The previous mirror tables had shapes that did not match
-- the GORM models (notably activities.id was BIGINT, and several GORM columns were
-- missing). This migration rebuilds the four service tables to match the models in
-- server/sql/11_interaction.sql exactly.
--
-- DESTRUCTIVE: drops existing interaction.companies/interactions/activities/customers
-- rows. Safe in unified mode because no live service data has been written to these
-- tables yet (they previously held only seed/demo rows). interaction.sync_state is
-- left untouched.
-- ----------------------------------------------------------------------------

CREATE SCHEMA IF NOT EXISTS interaction;

DROP TABLE IF EXISTS interaction.activities    CASCADE;
DROP TABLE IF EXISTS interaction.customers     CASCADE;
DROP TABLE IF EXISTS interaction.interactions  CASCADE;
DROP TABLE IF EXISTS interaction.companies     CASCADE;

-- Companies (GORM: Company)
CREATE TABLE interaction.companies (
  id             UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  name           TEXT,
  cdp_company_id UUID        NOT NULL REFERENCES app.companies(id) ON DELETE CASCADE,
  synced_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE UNIQUE INDEX interaction_companies_cdp_idx ON interaction.companies(cdp_company_id);

-- Interactions (GORM: Interaction)
CREATE TABLE interaction.interactions (
  id                     UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at             TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at             TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  name                   TEXT        NOT NULL DEFAULT '',
  company_id             UUID        NOT NULL REFERENCES interaction.companies(id) ON DELETE CASCADE,
  interaction_type       TEXT,
  cdp_reference_id       TEXT,
  rules                  JSONB       NOT NULL DEFAULT '{}',
  content                TEXT,
  default_recommendation JSONB       NOT NULL DEFAULT '{}',
  is_active              BOOLEAN     NOT NULL DEFAULT false,
  start_time             TIMESTAMPTZ,
  end_time               TIMESTAMPTZ,
  is_default             BOOLEAN     NOT NULL DEFAULT false,
  status                 TEXT,
  synced_at              TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE UNIQUE INDEX interaction_interactions_ref_idx  ON interaction.interactions(cdp_reference_id);
CREATE INDEX interaction_interactions_company_idx     ON interaction.interactions(company_id);

-- Activities (GORM: Activity)
CREATE TABLE interaction.activities (
  id                        UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at                TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at                TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  capsuite_sid              TEXT,
  capsuite_apid             TEXT,
  action                    TEXT        NOT NULL,
  correlated_interaction_id UUID        REFERENCES interaction.interactions(id) ON DELETE CASCADE,
  url_parameters            TEXT,
  json_parameters           TEXT,
  page_url                  TEXT,
  page_title                TEXT,
  synced_at                 TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX interaction_activities_corr_idx   ON interaction.activities(correlated_interaction_id);
CREATE INDEX interaction_activities_action_idx ON interaction.activities(action, created_at DESC);
CREATE INDEX interaction_activities_sid_idx    ON interaction.activities(capsuite_sid);

-- Customers (GORM: Customer; extra columns support seed/demo data)
CREATE TABLE interaction.customers (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  recommendations TEXT[],
  capsuite_sid    TEXT,
  interaction_id  UUID,
  company_id      UUID        REFERENCES interaction.companies(id) ON DELETE CASCADE,
  capsuite_apid   TEXT,
  email           TEXT,
  first_name      TEXT,
  last_name       TEXT,
  synced_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX interaction_customers_email_idx ON interaction.customers(company_id, LOWER(email)) WHERE email IS NOT NULL;

-- Project email_collection activities → app.popup_email_collected (Emails Collected tab).
CREATE OR REPLACE FUNCTION interaction.project_email_collection() RETURNS trigger AS $$
DECLARE
  v_json        jsonb;
  v_email       text;
  v_ref         text;
  v_cdp_company uuid;
  v_popup       app.popups%ROWTYPE;
BEGIN
  BEGIN
    v_json := NEW.json_parameters::jsonb;
  EXCEPTION WHEN others THEN
    v_json := '{}'::jsonb;
  END;

  v_email := NULLIF(btrim(lower(v_json->>'email')), '');
  IF v_email IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT i.cdp_reference_id, c.cdp_company_id
    INTO v_ref, v_cdp_company
    FROM interaction.interactions i
    JOIN interaction.companies c ON c.id = i.company_id
   WHERE i.id = NEW.correlated_interaction_id;

  IF v_cdp_company IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT * INTO v_popup
    FROM app.popups
   WHERE company_id = v_cdp_company AND cdp_reference_id = v_ref
   LIMIT 1;

  IF EXISTS (
    SELECT 1 FROM app.popup_email_collected
     WHERE company_id = v_cdp_company
       AND lower(email) = v_email
       AND popup_ref IS NOT DISTINCT FROM v_ref
  ) THEN
    RETURN NEW;
  END IF;

  INSERT INTO app.popup_email_collected (
    collected_at, company_id, popup_id, popup_name, popup_ref,
    email, first_name, last_name, phone,
    source_url, page_title, visitor_id, session_id,
    utm_source, utm_medium, utm_campaign, utm_term, utm_content,
    metadata
  ) VALUES (
    NEW.created_at, v_cdp_company, v_popup.id, v_popup.name, v_ref,
    v_email,
    NULLIF(v_json->>'first_name',''), NULLIF(v_json->>'last_name',''), NULLIF(v_json->>'phone',''),
    COALESCE(NULLIF(v_json->>'post_url',''), NULLIF(v_json->>'source_url','')),
    NULLIF(v_json->>'page_title',''),
    NEW.capsuite_apid, NEW.capsuite_sid,
    NULLIF(v_json->>'utm_source',''), NULLIF(v_json->>'utm_medium',''), NULLIF(v_json->>'utm_campaign',''),
    NULLIF(v_json->>'utm_term',''), NULLIF(v_json->>'utm_content',''),
    jsonb_build_object('source','interaction_activity','activity_id', NEW.id)
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS activities_project_email ON interaction.activities;
CREATE TRIGGER activities_project_email
  AFTER INSERT ON interaction.activities
  FOR EACH ROW
  WHEN (NEW.action = 'email_collection')
  EXECUTE FUNCTION interaction.project_email_collection();


-- ===================== migrations/2026-06-30_lite_standard_pro_plans.sql =====================

-- ============================================================================
-- 2026-06-30_lite_standard_pro_plans.sql
-- Replace the { free, paid } plan model with { lite, standard, pro }.
--
--   Lite     ($100/mo, 3-month trial) - entry tier  (was 'free')
--   Standard ($199/mo)               - growth tier   (was 'paid')
--   Pro      (contact sales)         - custom tier   (new)
--
-- Account remap: free -> lite (trial preserved), paid -> standard.
--
-- The trial / read-only state is now driven purely by plan_expires_at (a non-NULL
-- value means "in trial"), so it is tier-agnostic: Lite carries a 3-month trial,
-- Standard/Pro never do. There is still no in-app payment flow - the paid upgrade
-- is applied out-of-band by sales (set plan + clear plan_expires_at).
--
-- Idempotent migration for EXISTING databases. New databases get this state
-- directly from 02_accounts_auth.sql. Safe to run more than once.
-- Run with: psql "$DATABASE_URL" -f <file>
-- ============================================================================

BEGIN;

-- 1. Upsert the three new plans (copy/limits refreshed on re-run). Limits:
--    team_members=null => unlimited; ai_tokens are a generous monthly token
--    budget (gpt-5.4-mini @ $0.15/$0.60 per 1M => Lite 20M ~$4, Standard 100M ~$22).
INSERT INTO app.plans
  (id, name, price_display, period, badge, description, cta_label, cta_href, cta_external,
   is_highlighted, sort_order, trial_days, warning_days, features, limits, is_active)
VALUES
  ('lite', 'Lite', '$100', '/month', NULL,
   'Everything you need to get started with AI-powered customer data.',
   'Start 3-month free trial', '/register', false, false, 1, 90, 7,
   '["Unlimited team members","2 workspaces","Up to 10,000 customer profiles","AI Analyst","Intelligent Segmentation","UTM tracking","AI Content & Traffic Analysis","Dynamic Pop-up","200 credits / month"]'::jsonb,
   '{"profiles":10000,"campaigns":5,"ai_tokens":20000000,"team_members":null,"workspaces":2}'::jsonb,
   true),
  ('standard', 'Standard', '$199', '/month', 'Most popular',
   'For growing teams that need more scale and unlimited campaigns.',
   'Get started', '/register', false, true, 2, NULL, 7,
   '["Unlimited team members","5 workspaces","Up to 50,000 customer profiles","AI Analyst","Intelligent Segmentation","UTM tracking","AI Content & Traffic Analysis","Dynamic Pop-up","Unlimited email campaigns","1,000 credits / month"]'::jsonb,
   '{"profiles":50000,"campaigns":null,"ai_tokens":100000000,"team_members":null,"workspaces":5}'::jsonb,
   true),
  ('pro', 'Pro', 'Contact sales', '', NULL,
   'For high-volume teams. Custom profile and AI limits, tailored to you.',
   'Contact sales', 'mailto:support@clickcdp.com?subject=Upgrade to Pro', true, false, 3, NULL, 7,
   '["Unlimited team members","5+ workspaces","Custom customer profile volume","AI Analyst","Intelligent Segmentation","UTM tracking","AI Content & Traffic Analysis","Dynamic Pop-up","Unlimited email campaigns","Custom credits","Priority support"]'::jsonb,
   '{"profiles":null,"campaigns":null,"ai_tokens":null,"team_members":null,"workspaces":null}'::jsonb,
   true)
ON CONFLICT (id) DO UPDATE SET
  name=EXCLUDED.name, price_display=EXCLUDED.price_display, period=EXCLUDED.period,
  badge=EXCLUDED.badge, description=EXCLUDED.description, cta_label=EXCLUDED.cta_label,
  cta_href=EXCLUDED.cta_href, cta_external=EXCLUDED.cta_external,
  is_highlighted=EXCLUDED.is_highlighted, sort_order=EXCLUDED.sort_order,
  trial_days=EXCLUDED.trial_days, warning_days=EXCLUDED.warning_days,
  features=EXCLUDED.features, limits=EXCLUDED.limits, is_active=EXCLUDED.is_active;

-- 2. Remap existing accounts/workspaces onto the new tiers. plan_expires_at is
--    left untouched, so any in-flight Lite (was free) trial keeps its end date.
UPDATE app.accounts  SET plan = 'lite'     WHERE plan = 'free';
UPDATE app.accounts  SET plan = 'standard' WHERE plan = 'paid';
UPDATE app.companies SET plan = 'lite'     WHERE plan = 'free';
UPDATE app.companies SET plan = 'standard' WHERE plan = 'paid';

-- 3. New signups default to the Lite entry tier.
ALTER TABLE app.accounts ALTER COLUMN plan SET DEFAULT 'lite';

-- 4. Trial/upgrade stamping, made tier-agnostic. An account is "in trial" iff
--    plan_expires_at is set. Converting to paid (sales clears the expiry) stamps
--    plan_upgraded_at; (re)entering a trial clears it.
CREATE OR REPLACE FUNCTION app.stamp_plan_upgraded_at()
RETURNS TRIGGER AS $$
BEGIN
  IF TG_OP = 'UPDATE'
     AND OLD.plan_expires_at IS NOT NULL
     AND NEW.plan_expires_at IS NULL THEN
    NEW.plan_upgraded_at := NOW();
  ELSIF NEW.plan_expires_at IS NOT NULL THEN
    NEW.plan_upgraded_at := NULL;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS accounts_stamp_plan_upgraded ON app.accounts;
CREATE TRIGGER accounts_stamp_plan_upgraded
  BEFORE INSERT OR UPDATE OF plan, plan_expires_at ON app.accounts
  FOR EACH ROW EXECUTE FUNCTION app.stamp_plan_upgraded_at();

-- 5. Retire the obsolete catalog rows (all FKs now point at the new tiers).
DELETE FROM app.plans WHERE id IN ('free', 'paid');

COMMIT;


-- ===================== migrations/2026-07-02_ai_quota_enforcement.sql =====================

-- 2026-07-02  Hard-enforce the per-account AI token limit.
-- ---------------------------------------------------------------------------
-- Plans advertise a monthly AI allowance (e.g. Lite 20,000,000 tokens = 200
-- credits / month). Until now that limit was tracked but never enforced. This
-- adds the single source of truth used by the app to block further AI spend
-- once the CURRENT CALENDAR MONTH's usage reaches the limit.
--
--   app.ai_quota(account_id) -> (used, token_limit, is_over)
--     used        = tokens spent this calendar month (app.ai_usage is account-
--                   scoped and survives workspace deletion, matching the billing
--                   "overall" totals).
--     token_limit = the account's effective ai_tokens limit: a per-account
--                   settings override wins over the plan catalog; NULL = unlimited
--                   (Pro / contact-sales), which is never over.
--     is_over      = TRUE only when a finite limit is set AND used >= limit.
--
-- Applies to EVERY account (existing and new) automatically: it reads live plan
-- limits, so no backfill is needed. Idempotent.
--   Run with: psql "$DATABASE_URL" -f <file>

CREATE OR REPLACE FUNCTION app.ai_quota(p_account_id UUID)
RETURNS TABLE(used BIGINT, token_limit BIGINT, is_over BOOLEAN)
LANGUAGE sql STABLE AS $$
  WITH lim AS (
    SELECT COALESCE(
             NULLIF(a.settings->'limit_overrides'->>'ai_tokens', '')::BIGINT,
             NULLIF(p.limits->>'ai_tokens', '')::BIGINT
           ) AS token_limit
      FROM app.accounts a
      JOIN app.plans    p ON p.id = a.plan
     WHERE a.id = p_account_id
  ),
  u AS (
    SELECT COALESCE(SUM(total_tokens), 0)::BIGINT AS used
      FROM app.ai_usage
     WHERE account_id  = p_account_id
       AND occurred_at >= date_trunc('month', now())
  )
  SELECT u.used,
         lim.token_limit,
         (lim.token_limit IS NOT NULL AND u.used >= lim.token_limit) AS is_over
    FROM u CROSS JOIN lim;
$$;

COMMENT ON FUNCTION app.ai_quota(UUID) IS
  'Per-account monthly AI token quota: returns (used this calendar month, effective token limit, is_over). NULL limit = unlimited.';


-- ===================== migrations/2026-07-02_chart_summary_data_hash.sql =====================

-- Adds app.chart_summaries.data_hash so cached AI chart explanations become
-- data-aware: the server fingerprints the chart data (title + type + preview) it
-- generated a summary from, and regenerates when that fingerprint changes instead
-- of serving a stale explanation forever. Existing rows get NULL, which never
-- matches a fingerprint and so forces a one-time regeneration on next view.
-- Matches server/sql/03_app_core.sql. Idempotent.
ALTER TABLE app.chart_summaries
  ADD COLUMN IF NOT EXISTS data_hash TEXT;


-- ===================== migrations/2026-07-02_ai_quota_billing_period.sql =====================

-- Count the AI token quota per BILLING PERIOD, not calendar month. Supersedes
-- 2026-07-02_ai_quota_enforcement.sql above:
--   • Paid accounts (plan_expires_at IS NULL) reset on the billing-day anniversary
--     of the upgrade date (plan_upgraded_at, falling back to account creation).
--   • Trial accounts (plan_expires_at set) get ONE flat allowance for the whole
--     trial, counted from account creation with no monthly reset (Lite: 200
--     credits total across the 90-day trial). Idempotent.
CREATE OR REPLACE FUNCTION app.ai_quota(p_account_id UUID)
RETURNS TABLE(used BIGINT, token_limit BIGINT, is_over BOOLEAN)
LANGUAGE sql STABLE AS $$
  WITH acct AS (
    SELECT a.created_date,
           a.plan_expires_at,
           a.plan_upgraded_at,
           COALESCE(
             NULLIF(a.settings->'limit_overrides'->>'ai_tokens', '')::BIGINT,
             NULLIF(p.limits->>'ai_tokens', '')::BIGINT
           ) AS token_limit
      FROM app.accounts a
      JOIN app.plans    p ON p.id = a.plan
     WHERE a.id = p_account_id
  ),
  win AS (
    SELECT
      CASE
        WHEN acct.plan_expires_at IS NOT NULL
          THEN acct.created_date
        ELSE
          COALESCE(acct.plan_upgraded_at, acct.created_date)
          + make_interval(months =>
              (EXTRACT(YEAR  FROM age(now(), COALESCE(acct.plan_upgraded_at, acct.created_date)))::INT * 12
             + EXTRACT(MONTH FROM age(now(), COALESCE(acct.plan_upgraded_at, acct.created_date)))::INT))
      END AS period_start
      FROM acct
  ),
  u AS (
    SELECT COALESCE(SUM(total_tokens), 0)::BIGINT AS used
      FROM app.ai_usage, win
     WHERE account_id  = p_account_id
       AND occurred_at >= win.period_start
  )
  SELECT u.used,
         acct.token_limit,
         (acct.token_limit IS NOT NULL AND u.used >= acct.token_limit) AS is_over
    FROM u CROSS JOIN acct;
$$;

COMMENT ON FUNCTION app.ai_quota(UUID) IS
  'Per-account AI token quota over the current BILLING PERIOD: paid accounts reset on their billing-day anniversary; trial accounts get one flat allowance for the whole trial. Returns (used this period, effective token limit, is_over). NULL limit = unlimited.';
